//! Dispatch wrappers + registration for baracuda-kernels-sys-backed
//! kernels. Sibling to `dispatch::register_cuda_kernels` (PTX path) —
//! each kernel here registers as an alternative at the same
//! `(op_kind, dtypes, BackendId::Cuda)` key. Phase 7.6 step 9a's
//! append-on-register semantics keep them composable; step 9b's
//! route picker ranks by `PrecisionGuarantee` + telemetry.
//!
//! The boilerplate-explosion in this file (50+ unary kinds × 4
//! dtypes, plus binary / ternary / etc.) is generated by per-family
//! macros — adding a new (op, dtype) entry is one manifest line
//! here + one matching line in `fuel-cuda-backend::baracuda`.

#![cfg(feature = "cuda")]

use std::sync::{Arc, RwLock};

use fuel_ir::{Layout, Error, Result, probe::BackendId};
use fuel_ir::dispatch::OpKind;
use fuel_ir::DType;

use crate::kernel::{KernelBindingTable, OpParams};
use fuel_memory::Storage;

// Re-use the storage-helpers from dispatch.rs so we read/write
// CudaStorageBytes the same way the PTX wrappers do.
use crate::dispatch::{cuda_input, cuda_output, read_storage, write_storage};

/// Generate one CUDA unary dispatch wrapper that adapts a baracuda
/// `fn(&CudaStorageBytes, Option<&Layout>) -> Result<CudaStorageBytes>`
/// kernel into the `KernelRef` signature the binding table expects.
///
/// Arguments:
/// - `$wrapper_name` — the function symbol to emit.
/// - `$baracuda_fn` — fully-qualified path to the baracuda kernel
///   function (e.g. `fuel_cuda_backend::baracuda::elementwise::unary_neg_f32`).
macro_rules! cuda_unary_baracuda_wrapper {
    ($wrapper_name:ident, $baracuda_fn:path) => {
        pub fn $wrapper_name(
            inputs: &[Arc<RwLock<Storage>>],
            outputs: &mut [Arc<RwLock<Storage>>],
            layouts: &[Layout],
            _params: &OpParams,
        ) -> Result<()> {
            if inputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(stringify!($wrapper_name), ": expected 1 input, got {}"),
                    inputs.len(),
                ))
                .bt());
            }
            if outputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(stringify!($wrapper_name), ": expected 1 output, got {}"),
                    outputs.len(),
                ))
                .bt());
            }
            let layout = layouts.first();
            let in_guard = read_storage(&inputs[0])?;
            let mut out_guard = write_storage(&outputs[0])?;
            let src_cuda = cuda_input(&in_guard)?;
            let out_cuda = cuda_output(&mut out_guard)?;
            // Write-into-output (CapturedRun): the `_into` driver writes into
            // the executor-provided outputs[0] — no alloc + swap.
            $baracuda_fn(src_cuda, layout, out_cuda)
        }
    };
}

/// Generate one CUDA in-place unary dispatch wrapper. Phase 3e of
/// in-place ops infrastructure. The executor's `WorkItemKind::InplaceKernel`
/// arm passes the target Arc as `outputs[0]` with `inputs=[]`; the
/// wrapper acquires the target's write lock and calls the baracuda
/// in-place kernel (same baracuda symbol as the non-inplace cousin,
/// but with src_ptr == dst_ptr).
macro_rules! cuda_unary_inplace_baracuda_wrapper {
    ($wrapper_name:ident, $baracuda_fn:path) => {
        pub fn $wrapper_name(
            inputs: &[Arc<RwLock<Storage>>],
            outputs: &mut [Arc<RwLock<Storage>>],
            _layouts: &[Layout],
            _params: &OpParams,
        ) -> Result<()> {
            if !inputs.is_empty() || outputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(stringify!($wrapper_name),
                        ": expected 0 inputs + 1 output (target adopted by executor), got {} + {}"),
                    inputs.len(), outputs.len(),
                ))
                .bt());
            }
            let mut out_guard = write_storage(&outputs[0])?;
            let out_cuda = cuda_output(&mut out_guard)?;
            $baracuda_fn(out_cuda)
        }
    };
}

/// Generate one CUDA binary dispatch wrapper. Writes the kernel output
/// directly into the executor-provided `outputs[0]` buffer via the
/// baracuda `_into` (write-into) driver — no internal alloc + swap.
///
/// Byte-identical to the prior alloc-and-replace for normal realizes (the
/// executor pre-sizes `outputs[0]` from the node's output shape), and it
/// saves one device allocation per op. Crucially, it is the enabler for
/// persistent-output CUDA-graph capture: in the executor's capture mode
/// `outputs[0]` is a FIXED-ADDRESS persistent buffer written in place, so
/// no device allocation happens inside the capture scope (where both
/// alloc and host sync are illegal).
macro_rules! cuda_binary_baracuda_wrapper {
    ($wrapper_name:ident, $baracuda_into_fn:path) => {
        pub fn $wrapper_name(
            inputs: &[Arc<RwLock<Storage>>],
            outputs: &mut [Arc<RwLock<Storage>>],
            layouts: &[Layout],
            _params: &OpParams,
        ) -> Result<()> {
            if inputs.len() != 2 {
                return Err(Error::Msg(format!(
                    concat!(stringify!($wrapper_name), ": expected 2 inputs, got {}"),
                    inputs.len(),
                ))
                .bt());
            }
            if outputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(stringify!($wrapper_name), ": expected 1 output, got {}"),
                    outputs.len(),
                ))
                .bt());
            }
            let lhs_layout = layouts.first();
            let rhs_layout = layouts.get(1);
            let lhs_guard = read_storage(&inputs[0])?;
            let rhs_guard = read_storage(&inputs[1])?;
            let mut out_guard = write_storage(&outputs[0])?;
            let lhs_cuda = cuda_input(&lhs_guard)?;
            let rhs_cuda = cuda_input(&rhs_guard)?;
            let out_cuda = cuda_output(&mut out_guard)?;
            $baracuda_into_fn(lhs_cuda, rhs_cuda, lhs_layout, rhs_layout, out_cuda)
        }
    };
}

/// Generate a CUDA RoPE dispatch wrapper that pulls
/// `(outer_count, seq, head_dim)` from `OpParams::Rope` and
/// forwards to a baracuda RoPE kernel.
macro_rules! cuda_rope_baracuda_wrapper {
    ($wrapper_name:ident, $baracuda_fn:path) => {
        pub fn $wrapper_name(
            inputs: &[Arc<RwLock<Storage>>],
            outputs: &mut [Arc<RwLock<Storage>>],
            layouts: &[Layout],
            params: &OpParams,
        ) -> Result<()> {
            if inputs.len() != 1 || outputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(
                        stringify!($wrapper_name),
                        ": expected 1 input + 1 output, got {} + {}",
                    ),
                    inputs.len(), outputs.len(),
                ))
                .bt());
            }
            let (outer_count, seq, head_dim) = match params {
                OpParams::Rope { outer_count, seq, head_dim } => {
                    (*outer_count, *seq, *head_dim)
                }
                other => {
                    return Err(Error::Msg(format!(
                        concat!(
                            stringify!($wrapper_name),
                            ": expected OpParams::Rope, got {:?}",
                        ),
                        other,
                    ))
                    .bt());
                }
            };
            let layout = layouts.first();
            let in_guard = read_storage(&inputs[0])?;
            let mut out_guard = write_storage(&outputs[0])?;
            let src_cuda = cuda_input(&in_guard)?;
            let out_cuda = cuda_output(&mut out_guard)?;
            // Write-into-output (CapturedRun): `_into` writes into outputs[0].
            $baracuda_fn(src_cuda, layout, outer_count, seq, head_dim, out_cuda)
        }
    };
}

/// Generate a CUDA FUSED `FusedOps::ROPE` dispatch wrapper. Three inputs
/// `(x, cos, sin)`; `OpParams::Rope { outer_count, seq, head_dim }` is
/// derived generically from `x`'s real shape by `pipelined.rs`'s
/// `Op::Fused(_, FusedOpParams::Rope)` arm — the SAME backend-agnostic param
/// plumbing every other `FusedOps::ROPE` candidate (CPU included) uses, so
/// no new param-translation code is needed here. Fuel's cos/sin are
/// FULL-WIDTH `[seq, head_dim]` (`Tensor::rope_with_tables`'s hard assert);
/// `$driver` (a `rope_apply_fused_<dt>_into`) narrows them to baracuda's
/// half-width convention before launch — see
/// `fuel_cuda_backend::baracuda::attention`'s module note for the
/// correctness derivation. Mirrors the verification-harness-local
/// `rope_apply_wrapper!` in `fkc/verify/harness.rs` (Task 4.6), promoted
/// here to the shared PRODUCTION `CudaLinkRegistry` — that promotion was
/// explicitly out of scope for Task 4.6 and is what this registration does.
macro_rules! cuda_rope_apply_fused_baracuda_wrapper {
    ($wrapper_name:ident, $driver:path) => {
        pub fn $wrapper_name(
            inputs: &[Arc<RwLock<Storage>>],
            outputs: &mut [Arc<RwLock<Storage>>],
            _layouts: &[Layout],
            params: &OpParams,
        ) -> Result<()> {
            if inputs.len() != 3 || outputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(
                        stringify!($wrapper_name),
                        ": expected 3 inputs (x, cos, sin) + 1 output, got {} + {}",
                    ),
                    inputs.len(), outputs.len(),
                ))
                .bt());
            }
            let (outer_count, seq, head_dim) = match params {
                OpParams::Rope { outer_count, seq, head_dim } => {
                    (*outer_count, *seq, *head_dim)
                }
                other => {
                    return Err(Error::Msg(format!(
                        concat!(
                            stringify!($wrapper_name),
                            ": expected OpParams::Rope, got {:?}",
                        ),
                        other,
                    ))
                    .bt());
                }
            };
            let x_guard = read_storage(&inputs[0])?;
            let cos_guard = read_storage(&inputs[1])?;
            let sin_guard = read_storage(&inputs[2])?;
            let mut out_guard = write_storage(&outputs[0])?;
            let x_cuda = cuda_input(&x_guard)?;
            let cos_cuda = cuda_input(&cos_guard)?;
            let sin_cuda = cuda_input(&sin_guard)?;
            let out_cuda = cuda_output(&mut out_guard)?;
            // Write-into-output (CapturedRun): `_into` writes into outputs[0].
            $driver(x_cuda, cos_cuda, sin_cuda, outer_count, seq, head_dim, out_cuda)
        }
    };
}

/// Generate a CUDA index_select dispatch wrapper. Two inputs
/// `(src, indices)`; pulls the shape params from
/// `OpParams::IndexSelect`.
macro_rules! cuda_index_select_baracuda_wrapper {
    ($wrapper_name:ident, $baracuda_fn:path) => {
        pub fn $wrapper_name(
            inputs: &[Arc<RwLock<Storage>>],
            outputs: &mut [Arc<RwLock<Storage>>],
            _layouts: &[Layout],
            params: &OpParams,
        ) -> Result<()> {
            if inputs.len() != 2 || outputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(
                        stringify!($wrapper_name),
                        ": expected 2 inputs + 1 output, got {} + {}",
                    ),
                    inputs.len(), outputs.len(),
                ))
                .bt());
            }
            let (outer_count, source_dim_size, n_indices, inner_count) = match params {
                OpParams::IndexSelect { outer_count, source_dim_size, n_indices, inner_count } => {
                    (*outer_count, *source_dim_size, *n_indices, *inner_count)
                }
                other => {
                    return Err(Error::Msg(format!(
                        concat!(
                            stringify!($wrapper_name),
                            ": expected OpParams::IndexSelect, got {:?}",
                        ),
                        other,
                    ))
                    .bt());
                }
            };
            let src_guard = read_storage(&inputs[0])?;
            let idx_guard = read_storage(&inputs[1])?;
            if idx_guard.dtype != DType::U32 {
                return Err(Error::Msg(format!(
                    concat!(
                        stringify!($wrapper_name),
                        ": indices must be U32, got {:?}",
                    ),
                    idx_guard.dtype,
                ))
                .bt());
            }
            let mut out_guard = write_storage(&outputs[0])?;
            let src_cuda = cuda_input(&src_guard)?;
            let idx_cuda = cuda_input(&idx_guard)?;
            let out_cuda = cuda_output(&mut out_guard)?;
            // Write-into-output (CapturedRun): `_into` writes into outputs[0].
            $baracuda_fn(
                src_cuda, idx_cuda, outer_count, source_dim_size, n_indices, inner_count, out_cuda,
            )
        }
    };
}

