// ===========================================================================
// Affine — `y = mul * x + add` with scalar (mul, add) per OpParams::Affine
// ===========================================================================
//
// Per-dtype wrappers; baracuda's FFI carries (a, b) in the natural
// per-dtype arithmetic type (f32 for f16/bf16 storage; f64 for f64
// storage; per-element int type for i32/i64/u8). The wrappers cast
// Fuel's `(f64, f64)` OpParams down to the right type at the FFI
// boundary.

macro_rules! cuda_affine_baracuda_wrapper {
    ($wrapper_name:ident, $baracuda_fn:path, $scalar_cast:expr $(,)?) => {
        pub fn $wrapper_name(
            inputs: &[Arc<RwLock<Storage>>],
            outputs: &mut [Arc<RwLock<Storage>>],
            layouts: &[Layout],
            params: &OpParams,
        ) -> Result<()> {
            if inputs.len() != 1 || outputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(stringify!($wrapper_name), ": expected 1 input + 1 output, got {} + {}"),
                    inputs.len(), outputs.len(),
                )).bt());
            }
            let (mul_f64, add_f64) = match params {
                OpParams::Affine { mul, add } => (*mul, *add),
                other => {
                    return Err(Error::Msg(format!(
                        concat!(stringify!($wrapper_name), ": expected OpParams::Affine, got {:?}"),
                        other,
                    )).bt());
                }
            };
            let cast = $scalar_cast;
            let mul = cast(mul_f64);
            let add = cast(add_f64);
            let layout = layouts.first();
            let in_guard = read_storage(&inputs[0])?;
            let mut out_guard = write_storage(&outputs[0])?;
            let src_cuda = cuda_input(&in_guard)?;
            let out_cuda = cuda_output(&mut out_guard)?;
            // Write-into-output (CapturedRun): `_into` writes into outputs[0].
            $baracuda_fn(src_cuda, layout, mul, add, out_cuda)
        }
    };
}

pub mod affine {
    use super::*;
    use fuel_cuda_backend::baracuda::affine as bk;

    cuda_affine_baracuda_wrapper!(affine_f32, bk::affine_f32_into, |v: f64| v as f32);
    cuda_affine_baracuda_wrapper!(affine_f64, bk::affine_f64_into, |v: f64| v);
    cuda_affine_baracuda_wrapper!(affine_f16, bk::affine_f16_into, |v: f64| v as f32);
    cuda_affine_baracuda_wrapper!(affine_bf16, bk::affine_bf16_into, |v: f64| v as f32);
    cuda_affine_baracuda_wrapper!(affine_i32, bk::affine_i32_into, |v: f64| v as i32);
    cuda_affine_baracuda_wrapper!(affine_i64, bk::affine_i64_into, |v: f64| v as i64);
    cuda_affine_baracuda_wrapper!(affine_u8, bk::affine_u8_into, |v: f64| v as u8);

    // In-place affine — Phase 3d of the in-place ops infrastructure.
    // baracuda's `affine_inplace_{f32,f64}_run` symbols take a single
    // pointer (`y` = read+write). The executor's
    // `WorkItemKind::InplaceKernel` arm passes the target Arc as
    // `outputs[0]` with `inputs=[]`; we acquire its write lock and
    // mutate through `bytes_mut()` (via `cuda_output` which returns
    // `&mut CudaStorageBytes`).
    //
    // alpha.62 ships all 4 FP dtypes (f32/f64/bf16/f16); the
    // half-precision variants pivot scalars through f32 at the FFI
    // boundary. Closes the only known in-place ops gap from the
    // 2026-05-30 baracuda ask (Item 1).
    macro_rules! cuda_affine_inplace_baracuda_wrapper {
        ($wrapper_name:ident, $baracuda_fn:path, $scalar_cast:expr $(,)?) => {
            pub fn $wrapper_name(
                inputs: &[Arc<RwLock<Storage>>],
                outputs: &mut [Arc<RwLock<Storage>>],
                _layouts: &[Layout],
                params: &OpParams,
            ) -> Result<()> {
                if !inputs.is_empty() || outputs.len() != 1 {
                    return Err(Error::Msg(format!(
                        concat!(stringify!($wrapper_name),
                            ": expected 0 inputs + 1 output (target adopted by executor), got {} + {}"),
                        inputs.len(), outputs.len(),
                    )).bt());
                }
                let (mul_f64, add_f64) = match params {
                    OpParams::Affine { mul, add } => (*mul, *add),
                    other => {
                        return Err(Error::Msg(format!(
                            concat!(stringify!($wrapper_name), ": expected OpParams::Affine, got {:?}"),
                            other,
                        )).bt());
                    }
                };
                let cast = $scalar_cast;
                let mul = cast(mul_f64);
                let add = cast(add_f64);
                let mut out_guard = write_storage(&outputs[0])?;
                let out_cuda = cuda_output(&mut out_guard)?;
                $baracuda_fn(out_cuda, mul, add)
            }
        };
    }

    cuda_affine_inplace_baracuda_wrapper!(
        affine_inplace_f32, bk::affine_inplace_f32, |v: f64| v as f32);
    cuda_affine_inplace_baracuda_wrapper!(
        affine_inplace_f64, bk::affine_inplace_f64, |v: f64| v);
    cuda_affine_inplace_baracuda_wrapper!(
        affine_inplace_bf16, bk::affine_inplace_bf16, |v: f64| v as f32);
    cuda_affine_inplace_baracuda_wrapper!(
        affine_inplace_f16, bk::affine_inplace_f16, |v: f64| v as f32);
}

// ===========================================================================
// Cast — single wrapper across every (src_dt, dst_dt) pair baracuda exposes
// ===========================================================================
//
// Cast's binding-table key is `[src_dt, dst_dt]` (two dtypes, not the
// usual unary `[dt, dt]`). The wrapper reads both dtypes from the
// input/output Storage and dispatches into
// `fuel_cuda_backend::baracuda::cast::dispatch`, which picks the right
// FFI symbol from the 8×8 baracuda surface. One wrapper, many
// (per-pair) binding-table entries — same pattern as the PTX-backed
// `cast_cuda_wrapper` in [`crate::dispatch`].

pub mod cast {
    use super::*;
    use fuel_cuda_backend::baracuda::cast as bk;

    pub fn cast_baracuda_wrapper(
        inputs: &[Arc<RwLock<Storage>>],
        outputs: &mut [Arc<RwLock<Storage>>],
        _layouts: &[Layout],
        _params: &OpParams,
    ) -> Result<()> {
        if inputs.len() != 1 || outputs.len() != 1 {
            return Err(Error::Msg(format!(
                "cast_baracuda_wrapper: expected 1 input + 1 output, got {} + {}",
                inputs.len(),
                outputs.len(),
            ))
            .bt());
        }
        let in_guard = read_storage(&inputs[0])?;
        let mut out_guard = write_storage(&outputs[0])?;
        let src_dtype = in_guard.dtype;
        let dst_dtype = out_guard.dtype;
        let src_cuda = cuda_input(&in_guard)?;
        let result = bk::dispatch(src_cuda, src_dtype, dst_dtype)?;
        let out_cuda = cuda_output(&mut out_guard)?;
        *out_cuda = result;
        Ok(())
    }
}

/// Generate a CUDA softmax-last-dim dispatch wrapper that pulls
/// `(outer_count, last_dim)` from `OpParams::SoftmaxLastDim`
/// (or `LogSoftmaxLastDim`) and forwards to a baracuda softmax
/// kernel.
macro_rules! cuda_softmax_last_dim_baracuda_wrapper {
    ($wrapper_name:ident, $baracuda_fn:path) => {
        pub fn $wrapper_name(
            inputs: &[Arc<RwLock<Storage>>],
            outputs: &mut [Arc<RwLock<Storage>>],
            layouts: &[Layout],
            params: &OpParams,
        ) -> Result<()> {
            if inputs.len() != 1 || outputs.len() != 1 {
                return Err(Error::Msg(format!(
                    concat!(
                        stringify!($wrapper_name),
                        ": expected 1 input + 1 output, got {} + {}",
                    ),
                    inputs.len(), outputs.len(),
                ))
                .bt());
            }
            // Validate params shape (outer_count + last_dim are now
            // implicit in the layout — the wrapper consumes only the
            // discriminant to confirm we got the expected OpKind).
            match params {
                OpParams::SoftmaxLastDim { .. } | OpParams::LogSoftmaxLastDim { .. } => {}
                other => {
                    return Err(Error::Msg(format!(
                        concat!(
                            stringify!($wrapper_name),
                            ": expected OpParams::SoftmaxLastDim/LogSoftmaxLastDim, got {:?}",
                        ),
                        other,
                    ))
                    .bt());
                }
            }
            let layout = layouts.first().ok_or_else(|| {
                Error::Msg(concat!(
                    stringify!($wrapper_name),
                    ": SoftmaxLastDim requires an input layout (call with layouts[0])",
                ).to_string()).bt()
            })?;
            let in_guard = read_storage(&inputs[0])?;
            let mut out_guard = write_storage(&outputs[0])?;
            let src_cuda = cuda_input(&in_guard)?;
            let out_cuda = cuda_output(&mut out_guard)?;
            // Write-into-output (CapturedRun): `_into` writes into outputs[0].
            $baracuda_fn(src_cuda, layout, out_cuda)
        }
    };
}

